import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"踏罡步斗","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/能量类/踏罡步斗.md","filePath":"4.资源分区/6.技艺及称号/能量类/踏罡步斗.md"}'),d={name:"4.资源分区/6.技艺及称号/能量类/踏罡步斗.md"};function p(l,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"踏罡步斗",tabindex:"-1"},[s("踏罡步斗 "),e("a",{class:"header-anchor",href:"#踏罡步斗","aria-label":'Permalink to "踏罡步斗"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="踏罡步斗-1" tabindex="-1">踏罡步斗 <a class="header-anchor" href="#踏罡步斗-1" aria-label="Permalink to &quot;踏罡步斗&quot;">​</a></h1><p>踏罡步斗<br> D+750<br> 踏罡步斗，是禹步的一种。禹步是祷神仪礼中常用的一种步法动作，步法依北斗七星排列的位置而行步转折，宛如踏在罡星斗宿之上，又称“步罡踏斗”。踏罡步斗修习者需要按特定的规则顺序走 出步伐和站位，这样自身身体的经络就会打开，可以吸收自然界生物流失在空间中的零散能量，这种能量被叫做罡气。这种走步的手段称为踏罡步斗。只要步伐不被打乱，使用者就可以利用罡气长时间保持旺盛的精力，特定的步伐也可以让人吸入可以修复身体的罡气。</p><p>得炁：<br> 踏罡步斗实际上也是仙人盗的一种，作为一种练炁法门，修习者需要打熬肉身，定心沉志，千遍万遍得重复步法，最终在某一刻得炁，踏入修炼一途，踏罡步斗得炁，也叫天罡炁，不过这是指得炁方式来源于天罡，所修炼的炁并无特殊。人物开启能量池“炁”（qi），关键属性为耐力与感知，炁视为中性内力的一种变体，不具有内力得基础用法。<br> 炁的恢复方式：炁可以通过一次长休完全恢复或者打坐静功，后者每次消耗15分钟。做一个关键属性的判定，恢复等同于成功数的点数。以此每日回复的“炁”不可超过人物所拥有的“炁”的上限的三倍。</p><p>踏罡步斗：<br> 迅捷动作使用，持续一轮，在本轮中，人物将接下来两次能力所消耗的“炁”降低3点，最低为1点，这是人物依靠空间中的零散的能量代替支付了本该消耗的“炁”，同时，在维持踏罡步斗时，人物的精力也会更加旺盛，人物在强韧豁免上，获得4dp修行加值。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
